			"description": "The size of the border",
			"default": "3px"
		},
		"color": {
			"aliases": [
				"background"
			],
			"description": "The color of background",
			"example": "black",
			"default": "white"
		},
		"text color": {
			"description": "The color of the text",
			"example": "green",
			"default": "black"
		},
		"text align": {
			"description": "The alignment of the text (css text-align)",
			"example": "center",
			"default": "left"
		},
		"spacing": {
			"description": "The spacing of the letters"
		},
		"font": {
			"description": "The font of the text"
		},
		"font size": {
			"aliases": [
				"text size"
			],
			"description": "The size of the text"
		},
		"margin": {
			"description": "The size of the box's margin",
			"example": "30px",
			"default": "3px"
		},
		"top margin": {
			"description": "The size of the box's top margin"
		},
		"bottom margin": {
			"description": "The size of the box's bottom margin"
		},
		"left margin": {
			"description": "The size of the box's left margin"
		},
		"right margin": {
			"description": "The size of the box's right margin"
		},
		"height": {
			"description": "The height of the box",
			"example": "400px",
			"default": "''the height of the contents plus the margin''"
		},
		"max-height": {
			"description": "The maximum height of the box",
			"example": "800px"
		},
		"min-height": {
			"description": "The minimum height of the box",
			"example": "100px"
		},
		"width": {
			"description": "The width of the box",
			"default": "''the width of the text plus the margin or padding''"
		},
		"max-width": {
			"description": "The maximum width of the box"
		},
		"min-width": {
			"description": "The minimum width of the box"
		},
		"CSS": {
			"description": "Any additional CSS to use"
		}
	},
	"description": "This template produces a variety of boxes from preset options and from CSS.",
	"format": "inline"
}
</templatedata>

==Tracking category==
* {{Category link with count|Pages using box with unknown parameters}}

==See also==
